LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;
USE IEEE.NUMERIC_STD.ALL;

ENTITY fetch_stage IS
    GENERIC (
        WIDTH : NATURAL := 32;
        PC_RESET_VALUE : STD_LOGIC_VECTOR(31 DOWNTO 0) := (OTHERS => '0') -- PC reset value (0x00000000)
    );
    PORT (
        -- Clock and Reset
        clk                 : IN STD_LOGIC;
        rst                 : IN STD_LOGIC;

        -- Memory Data Input (from shared Von-Neumann memory)
        mem_data_in         : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);

        -- Jump/Branch Addresses
        jump_cond_addr      : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Conditional jump address
        int_data            : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Interrupt vector address
        sp_address          : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);

        -- Control Signals
        pc_en               : IN STD_LOGIC; -- PC enable signal
        JMP_in_ID           : IN STD_LOGIC; -- Jump immediate control
        branch_taken        : IN STD_LOGIC; -- Branch taken control
        load_pc_from_mem    : IN STD_LOGIC; -- for ret and rti
        is_int              : IN STD_LOGIC; -- Interrupt control
        Mem_Add_Src         : IN STD_LOGIC; -- 0: PC, 1: SP address
        assert_hlt          : IN STD_LOGIC; -- Assert halt signal

        -- Outputs to Memory
        mem_address         : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Address to Von-Neumann memory

        -- Outputs to next stage
        instruction         : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Fetched instruction (mem_data)
        pc_plus_one         : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0) -- PC+1 value
    );
END fetch_stage;

ARCHITECTURE fetch_stage_arch OF fetch_stage IS
    COMPONENT pc_reg IS
        GENERIC (
            WIDTH : NATURAL := 32;
            RESET_VALUE : STD_LOGIC_VECTOR(31 DOWNTO 0) := (OTHERS => '0')
        );
        PORT (
            pc_in : IN STD_LOGIC_VECTOR (WIDTH-1 DOWNTO 0);
            clk, pc_en, hlt, reset : IN STD_LOGIC;
            next_ins_address : OUT STD_LOGIC_VECTOR (WIDTH-1 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT Add_Sub IS
        PORT (
            data_in   : IN  STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);
            op_sel    : IN  STD_LOGIC_VECTOR(1 DOWNTO 0);
            data_out  : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT mux2to1_N IS
        GENERIC (
            WIDTH : NATURAL := 32
        );
        PORT (
            d0  : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);
            d1  : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);
            sel : IN STD_LOGIC;
            y   : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT HLT_module IS
        PORT (
            clk        : IN STD_LOGIC;
            rst        : IN STD_LOGIC;
            assert_hlt : IN STD_LOGIC;
            hlt_active : OUT STD_LOGIC
        );
    END COMPONENT;

    -- Internal Signals
    SIGNAL pc_current       : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Current PC value
    SIGNAL pc_incremented   : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- PC + 1
    SIGNAL hlt_signal       : STD_LOGIC; -- HLT status from HLT module

    -- MUX intermediate signals
    SIGNAL mux1_out         : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Output of first mux
    SIGNAL mux2_out         : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Output of second mux
    SIGNAL mux3_out         : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Output of third mux
    SIGNAL mux4_out         : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Output of fourth mux (PC input)

BEGIN
    hlt_unit: HLT_module
        PORT MAP (
            clk        => clk,
            rst        => rst,
            assert_hlt => assert_hlt,
            hlt_active => hlt_signal
        );

    -- Add_Sub Unit: Increment PC by 1
    pc_incrementer: Add_Sub
        PORT MAP (
            data_in  => pc_current,
            op_sel   => "01",                     -- Increment operation
            data_out => pc_incremented
        );

    -- MUX 1: Select between PC+1 and jump immediate (mem_data)
    mux1: mux2to1_N
        GENERIC MAP (WIDTH => WIDTH)
        PORT MAP (
            d0  => pc_incremented,  -- PC+1
            d1  => mem_data_in,     -- Jump immediate from memory
            sel => JMP_in_ID,
            y   => mux1_out
        );

    -- MUX 2: Select between mux1 output and conditional jump address
    mux2: mux2to1_N
        GENERIC MAP (WIDTH => WIDTH)
        PORT MAP (
            d0  => mux1_out,
            d1  => jump_cond_addr,  -- Conditional jump address
            sel => branch_taken,
            y   => mux2_out
        );

    -- MUX 3: Select between mux2 output and return address (mem_data)
    mux3: mux2to1_N
        GENERIC MAP (WIDTH => WIDTH)
        PORT MAP (
            d0  => mux2_out,
            d1  => mem_data_in,     -- Return address from memory
            sel => load_pc_from_mem,
            y   => mux3_out
        );

    -- MUX 4: Select between mux3 output and interrupt vector
    mux4: mux2to1_N
        GENERIC MAP (WIDTH => WIDTH)
        PORT MAP (
            d0  => mux3_out,
            d1  => int_data,        -- Interrupt vector address
            sel => is_int,
            y   => mux4_out
        );

    -- PC Register Instance
    pc_register: pc_reg
        GENERIC MAP (
            WIDTH => WIDTH,
            RESET_VALUE => PC_RESET_VALUE
        )
        PORT MAP (
            pc_in            => mux4_out,
            clk              => clk,
            pc_en            => pc_en,
            hlt              => hlt_signal,
            reset            => rst,
            next_ins_address => pc_current
        );

    -- MUX 5: Select memory address between PC and SP address
    mux5_mem_addr: mux2to1_N
        GENERIC MAP (WIDTH => WIDTH)
        PORT MAP (
            d0  => pc_current, -- PC address
            d1  => sp_address,                   -- SP address from memory stage
            sel => Mem_Add_Src,
            y   => mem_address
        );

    -- Output Assignments
    instruction   <= mem_data_in;     -- Pass through memory data as instruction
    pc_plus_one   <= pc_incremented;  -- Output PC+1 for next stage
END fetch_stage_arch;

