LIBRARY IEEE;
USE IEEE.std_logic_1164.ALL;
USE IEEE.STD_LOGIC_UNSIGNED.ALL;
USE IEEE.numeric_std.ALL;

ENTITY pc_reg IS
    GENERIC (
        WIDTH : NATURAL := 32;
        RESET_VALUE : STD_LOGIC_VECTOR(31 DOWNTO 0) := (OTHERS => '0') -- Default reset value (0x00000000)
    );
    PORT (
        pc_in : IN STD_LOGIC_VECTOR (WIDTH-1 DOWNTO 0);
        clk, pc_en, hlt, reset : IN STD_LOGIC;
        next_ins_address : OUT STD_LOGIC_VECTOR (WIDTH-1 DOWNTO 0) := (OTHERS => '0')
    );
END ENTITY pc_reg;

ARCHITECTURE pc_reg_arch OF pc_reg IS
    SIGNAL pc_register : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0) := RESET_VALUE;
BEGIN
    PROCESS (clk, reset)
    BEGIN
        IF (reset = '1') THEN
            pc_register <= RESET_VALUE;
        ELSIF (RISING_EDGE(clk)) THEN
            IF (hlt = '0' AND pc_en = '1') THEN
                pc_register <= pc_in;
            END IF;
        END IF;
    END PROCESS;

    next_ins_address <= pc_register;

END ARCHITECTURE;

