LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;

ENTITY Control_Unit IS
    PORT (
        Opcode : IN STD_LOGIC_VECTOR(4 DOWNTO 0);

        -- 1. DECODE / HAZARD SIGNALS
        is_two_word_op : OUT STD_LOGIC; -- True for instructions using Immediate/Offset (LDM, LDD, STD, JMP, CALL)
        JMP_IN_ID : OUT STD_LOGIC; -- Triggers Unconditional Jump immediately in Decode stage
        is_branch : OUT STD_LOGIC; -- Triggers Conditional Branch logic (JZ, JN, JC) in Execute

        load_pc_from_mem : OUT STD_LOGIC; -- True for RET/RTI. Tells Fetch to load Next PC from Memory Bus.
        assert_hlt : OUT STD_LOGIC; -- Freezes the PC.

        -- 2. EXECUTE STAGE SIGNALS
        alu_op : OUT STD_LOGIC; -- '0': Force ADD (Addr Calc), '1': Look at Opcode for ALUSel
        alu_src_b : OUT STD_LOGIC; -- '0': Register B, '1': Immediate/Offset
        jump_inst : OUT STD_LOGIC_VECTOR(1 DOWNTO 0); -- Branch Type: 01=JZ, 10=JN, 11=JC

        io_read : OUT STD_LOGIC; -- IN instruction (Read from Input Port)
        io_write : OUT STD_LOGIC; -- OUT instruction (Write to Output Port)

        -- Flag & Interrupt Controls
        restore_flags : OUT STD_LOGIC; -- RTI: Restore CCR from Shadow Register
        str_flags : OUT STD_LOGIC; -- INT: Store CCR to Shadow Register
        is_int : OUT STD_LOGIC; -- Interrupt: Forces Muxes to select Int Vector & Index

        -- PC Saving Controls (For CALL / INT)
        use_pc : OUT STD_LOGIC; -- '1': Write PC to Stack/Reg. '0': Write ALU Result.
        use_pc_plus_two : OUT STD_LOGIC; -- '1': Save PC+2 (CALL). '0': Save PC+1 (INT).

        -- 3. MEMORY STAGE SIGNALS
        mem_read : OUT STD_LOGIC; -- Read from Data Memory
        mem_write : OUT STD_LOGIC; -- Write to Data Memory

        use_sp_add : OUT STD_LOGIC; -- '1': Use Stack Pointer as Address. '0': Use ALU Result.
        mem_add_src : OUT STD_LOGIC; -- '1': Access Data Memory. '0': Access Instruction Memory (Fetch).

        -- Stack Signals
        sp_en : OUT STD_LOGIC; -- Enable SP Register Update
        inc_sp : OUT STD_LOGIC; -- '1': Increment (+1). '0': Decrement (-1).
        use_old_sp : OUT STD_LOGIC; -- '1': Use Value BEFORE change (PUSH). '0': Use Value AFTER change (POP).

        -- 4. WRITE-BACK STAGE SIGNALS
        reg_write : OUT STD_LOGIC; -- Enable writing to Register File
        mem_to_reg : OUT STD_LOGIC; -- '1': Write Memory Data. '0': Write ALU Result.
        is_swap : OUT STD_LOGIC -- Triggers Swap FSM in Write-Back (2-cycle write)
    );
END Control_Unit;

ARCHITECTURE Behavioral OF Control_Unit IS
BEGIN
    PROCESS (Opcode)
    BEGIN
        -- 1. DEFAULT VALUES (Safe State / NOP)
        -- Reset all triggers to '0' to prevent accidental writes or jumps.
        is_two_word_op <= '0';
        JMP_IN_ID <= '0';
        is_branch <= '0';
        load_pc_from_mem <= '0';
        assert_hlt <= '0';

        alu_op <= '1'; -- Default to Decode (safest)
        alu_src_b <= '0'; -- Default to Register
        jump_inst <= "00";

        io_read <= '0';
        io_write <= '0';
        restore_flags <= '0';
        str_flags <= '0';
        is_int <= '0';

        use_pc <= '0';
        use_pc_plus_two <= '0';

        mem_read <= '0';
        mem_write <= '0';
        use_sp_add <= '0';
        mem_add_src <= '0';

        sp_en <= '0';
        inc_sp <= '0';
        use_old_sp <= '0';
        reg_write <= '0';
        mem_to_reg <= '0';
        is_swap <= '0';

        -- 2. INSTRUCTION DECODING
        CASE Opcode IS
            WHEN "00000" => NULL; -- NOP: Do nothing.

            WHEN "00001" => assert_hlt <= '1'; -- HLT: Freeze PC.

                -- SETC 
            WHEN "00010" => alu_op <= '1'; -- ALU Ctrl will see opcode and set C flag.

                -- OUT Rdst
            WHEN "00101" =>
                io_write <= '1'; -- Enable Output Port Tri-state
                alu_op <= '0'; -- Op doesn't matter, data tapped before ALU.

                -- IN Rdst
            WHEN "00110" =>
                reg_write <= '1'; -- Write to Dest Reg
                io_read <= '1'; -- Select Input Port at Mux
                alu_op <= '0';

                -- SWAP Rsrc, Rdst
            WHEN "00111" =>
                is_swap <= '1'; -- Trigger WB Stage FSM
                reg_write <= '1'; -- Enable Write (Cycle 1)
                alu_op <= '1'; -- Decode (Pass A through ALU)

                -- LDM Rdst, Imm (Load Immediate)
            WHEN "01110" =>
                is_two_word_op <= '1'; -- Fetch Immediate next
                reg_write <= '1'; -- Write to Reg
                alu_op <= '1'; -- Decode (Pass B)
                alu_src_b <= '1'; -- Select Immediate Mux

                -- ARITHMETIC OPERATIONS

                -- Standard R-Type (ADD, SUB, AND, NOT, INC)
            WHEN "00011" | "00100" | "01000" | "01001" | "01010" =>
                reg_write <= '1'; -- Save Result
                alu_op <= '1'; -- ALU Ctrl Decodes Function

                -- MOV Rsrc, Rdst (Register Copy)
            WHEN "01011" =>
                reg_write <= '1';
                alu_op <= '1'; -- ALU Ctrl Decodes to PASS_A

                -- IADD Rdst, Rsrc, Imm (Immediate Add)
            WHEN "11001" =>
                is_two_word_op <= '1'; -- Fetch Imm
                reg_write <= '1';
                alu_op <= '1'; -- ALU Ctrl Decodes to ADD
                alu_src_b <= '1'; -- Select Imm input

                -- MEMORY OPERATIONS

                -- LDD Rdst, Offset(Rsrc) (Load Data Direct)
            WHEN "01111" =>
                is_two_word_op <= '1'; -- Fetch Offset
                mem_read <= '1'; -- Read RAM
                reg_write <= '1'; -- Write to Reg
                mem_to_reg <= '1'; -- Select RAM Data

                alu_op <= '0'; -- Force ADD (Base + Offset)
                alu_src_b <= '1'; -- Select Offset
                use_sp_add <= '0'; -- Use ALU Address
                mem_add_src <= '1'; -- Address comes from Data Path

                -- STD Rsrc1, Offset(Rsrc2) (Store Data Direct)
            WHEN "10000" =>
                is_two_word_op <= '1'; -- Fetch Offset
                mem_write <= '1'; -- Write RAM

                alu_op <= '0'; -- Force ADD (Base + Offset)
                alu_src_b <= '1'; -- Select Offset
                use_sp_add <= '0';
                mem_add_src <= '1';

                -- STACK OPERATIONS

                -- PUSH Rdst
                -- Logic: Store at current SP, THEN Decrement SP.
            WHEN "01100" =>
                mem_write <= '1';
                sp_en <= '1';
                inc_sp <= '0'; -- Decrement (-1)
                use_old_sp <= '1'; -- Use OLD Value for Address

                use_sp_add <= '1'; -- Address comes from SP
                mem_add_src <= '1';

                -- POP Rdst
                -- Logic: Increment SP, THEN Load from new SP.
            WHEN "01101" =>
                mem_read <= '1';
                reg_write <= '1';
                mem_to_reg <= '1'; -- Data from Mem

                sp_en <= '1';
                inc_sp <= '1'; -- Increment (+1)
                use_old_sp <= '0'; -- Use NEW Value for Address

                use_sp_add <= '1';
                mem_add_src <= '1';

                -- CONTROL FLOW

                -- JMP Address (Unconditional)
            WHEN "10100" =>
                is_two_word_op <= '1';
                JMP_IN_ID <= '1'; -- Tell Fetch to use Immediate Address NOW.

                -- BRANCHES (Conditional: JZ, JN, JC)
