            WHEN "10101" =>
                is_two_word_op <= '1';
                JMP_IN_ID <= '1'; -- Unconditional Jump Logic

                mem_write <= '1'; -- Push to Stack
                sp_en <= '1';
                inc_sp <= '0';
                use_old_sp <= '1'; -- PUSH Logic
                use_sp_add <= '1';
                mem_add_src <= '1';

                use_pc <= '1'; -- Select PC instead of Reg Data
