                sp_en <= '1';
                inc_sp <= '1';
                use_old_sp <= '0'; -- POP Logic
                use_sp_add <= '1';
                mem_add_src <= '1';

            WHEN OTHERS => NULL;
        END CASE;
    END PROCESS;
