library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity ALU is
    port (
        op_a     : in  std_logic_vector(31 downto 0);
        op_b     : in  std_logic_vector(31 downto 0);
        alu_sel  : in  std_logic_vector(3 downto 0);
        result   : out std_logic_vector(31 downto 0);
        flags    : out std_logic_vector(2 downto 0) -- 2: Carry, 1: Negative, 0: Zero
    );
end ALU;

architecture Behavioral of ALU is
    signal res_temp : std_logic_vector(32 downto 0); -- 33 bits to capture carry
    signal a_ext    : std_logic_vector(32 downto 0);
    signal b_ext    : std_logic_vector(32 downto 0);
begin

    a_ext <= '0' & op_a;
    b_ext <= '0' & op_b;

    process(op_a, op_b, alu_sel, a_ext, b_ext)
    begin
        -- Default values
        res_temp <= (others => '0');

        case alu_sel is
            when "0000" => -- ADD
                res_temp <= std_logic_vector(unsigned(a_ext) + unsigned(b_ext));

            when "0001" => -- SUB
                res_temp <= std_logic_vector(unsigned(a_ext) - unsigned(b_ext));

            when "0010" => -- AND
                res_temp <= '0' & (op_a and op_b);

            when "0011" => -- NOT
                res_temp <= '0' & (not op_a);

            when "0100" => -- INC
                res_temp <= std_logic_vector(unsigned(a_ext) + 1);

            when "0101" => -- PASS_A (MOV, OUT)
                res_temp <= a_ext;

            when "0110" => -- SETC
                res_temp <= (others => '0'); 
                -- Carry will be set in flags process

            when "0111" => -- PASS_B (LDM)
                res_temp <= b_ext;

            when others =>
                res_temp <= (others => '0');
        end case;
    end process;

    result <= res_temp(31 downto 0);

    -- Flags Logic
    process(res_temp, alu_sel)
    begin
        -- Zero Flag (Z is CCR<0>)
        if res_temp(31 downto 0) = x"00000000" then
            flags(0) <= '1';
        else
            flags(0) <= '0';
        end if;

        -- Negative Flag (N is CCR<1>)
        flags(1) <= res_temp(31);

        -- Carry Flag (C is CCR<2>)
        if alu_sel = "0110" then -- SETC
             flags(2) <= '1';
        elsif alu_sel = "0000" or alu_sel = "0001" or alu_sel = "0100" then -- ADD, SUB, INC
            flags(2) <= res_temp(32);
        else
            flags(2) <= '0'; -- Clear carry for logic ops
        end if;
    end process;

end Behavioral;

