library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity Add_Sub is
    port (
        data_in   : in  std_logic_vector(31 downto 0);
        op_sel  : in  std_logic_vector(1 downto 0); -- 00: Hold, 01: Inc (+1), 10: Dec (-1)
        data_out  : out std_logic_vector(31 downto 0)
    );
end Add_Sub;

architecture Behavioral of Add_Sub is
begin
    process(data_in, op_sel)
    begin
        case op_sel is
            when "01" => -- Increment
                data_out <= std_logic_vector(unsigned(data_in) + 1);
            when "10" => -- Decrement
                data_out <= std_logic_vector(unsigned(data_in) - 1);
            when others => -- Hold
                data_out <= data_in;
        end case;
    end process;
end Behavioral;

